const canvas = document.getElementById('physics-canvas');
const ctx = canvas.getContext('2d');
canvas.width = window.innerWidth;
canvas.height = window.innerHeight;

let particles = [];
const colors = ['#3b82f6', '#60a5fa', '#93c5fd', '#1d4ed8'];

const mouse = {
    x: canvas.width / 2,
    y: canvas.height / 2,
    radius: 300
};

window.addEventListener('mousemove', (e) => {
    mouse.x = e.x;
    mouse.y = e.y;
});

window.addEventListener('resize', () => {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    init();
});

class Particle {
    constructor() {
        this.x = Math.random() * canvas.width;
        this.y = Math.random() * canvas.height;
        this.size = Math.random() * 2 + 1;
        this.color = colors[Math.floor(Math.random() * colors.length)];
        this.velocity = {
            x: (Math.random() - 0.5) * 1.5,
            y: (Math.random() - 0.5) * 1.5
        };
    }

    draw() {
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2, false);
        ctx.fillStyle = this.color;
        ctx.fill();
    }

    update() {
        let dx = mouse.x - this.x;
        let dy = mouse.y - this.y;
        let distance = Math.sqrt(dx * dx + dy * dy);

        if (distance < mouse.radius) {
            let force = (mouse.radius - distance) / mouse.radius;
            let tangentialX = -dy / distance;
            let tangentialY = dx / distance;
            let accelerationX = (dx / distance) * force * 0.1;
            let accelerationY = (dy / distance) * force * 0.1;

            this.velocity.x += accelerationX + tangentialX * force * 0.15;
            this.velocity.y += accelerationY + tangentialY * force * 0.15;
        }

        this.velocity.x *= 0.98;
        this.velocity.y *= 0.98;

        this.x += this.velocity.x;
        this.y += this.velocity.y;

        if (this.x < 0) this.x = canvas.width;
        if (this.x > canvas.width) this.x = 0;
        if (this.y < 0) this.y = canvas.height;
        if (this.y > canvas.height) this.y = 0;

        this.draw();
    }
}

function init() {
    particles = [];
    let numParticles = Math.floor((canvas.width * canvas.height) / 8000);
    if (numParticles > 400) numParticles = 400;

    for (let i = 0; i < numParticles; i++) {
        particles.push(new Particle());
    }
}

function animate() {
    requestAnimationFrame(animate);
    ctx.fillStyle = 'rgba(240, 244, 248, 0.2)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    particles.forEach(particle => {
        particle.update();
    });
}

init();
animate();
